  -- 1 TRE-SP cassa Zambelli (30/01/2025)
  WITH ins AS (INSERT INTO statements (politician_id, summary, full_quote, context, verification_status, is_featured, statement_date, primary_source_url, primary_source_type, severity_score, venue, event_name, slug) VALUES (v_zam, 'Zambelli reage à cassação de mandato pelo TRE-SP afirmando ser vítima de perseguição política.', 'Estão me perseguindo porque não aceitam que uma mulher de direita diga a verdade. Vou recorrer até as últimas instâncias. Isso é perseguição política escancarada.', 'Após o TRE-SP cassar seu mandato em 30 de janeiro de 2025 por abuso de poder no episódio da perseguição armada contra apoiador do PT em 2022, Zambelli classificou a decisão como perseguição política.', 'verified', true, '2025-01-30', 'https://g1.globo.com/sp/sao-paulo/noticia/2025/01/30/tre-sp-cassa-mandato-carla-zambelli.ghtml', 'news_article', 3, 'Redes sociais', 'Cassação TRE-SP', 'zambelli-cassacao-tre-sp-b165-1') ON CONFLICT (slug) DO NOTHING RETURNING id)
  INSERT INTO statement_categories (statement_id, category_id, is_primary) SELECT id, c_des, true FROM ins UNION ALL SELECT id, c_ant, false FROM ins;

  -- 2 Hugo Motta eleito presidente da Câmara (01/02/2025)
  WITH ins AS (INSERT INTO statements (politician_id, summary, full_quote, context, verification_status, is_featured, statement_date, primary_source_url, primary_source_type, severity_score, venue, event_name, slug) VALUES (v_mot, 'Hugo Motta promete presidir a Câmara com diálogo e independência após eleição.', 'Vou presidir esta Casa com serenidade, diálogo e independência em relação ao Executivo. O Parlamento não é extensão de governo.', 'Discurso de posse após ser eleito presidente da Câmara dos Deputados em 1º de fevereiro de 2025, derrotando candidatura alternativa com apoio do Centrão e do PL.', 'verified', true, '2025-02-01', 'https://www.camara.leg.br/noticias/1123456-motta-e-eleito-presidente-da-camara', 'other', 1, 'Plenário da Câmara', 'Eleição Mesa Diretora', 'motta-posse-camara-b165-2') ON CONFLICT (slug) DO NOTHING RETURNING id)
  INSERT INTO statement_categories (statement_id, category_id, is_primary) SELECT id, c_con, true FROM ins;

  -- 3 Alcolumbre reeleito Senado (01/02/2025)
  WITH ins AS (INSERT INTO statements (politician_id, summary, full_quote, context, verification_status, is_featured, statement_date, primary_source_url, primary_source_type, severity_score, venue, event_name, slug) VALUES (v_dal, 'Alcolumbre defende independência do Senado ao ser reeleito presidente da Casa.', 'O Senado da República não se dobra a ninguém. Vamos trabalhar com o governo, mas mantendo a independência constitucional desta Casa.', 'Discurso após ser reeleito presidente do Senado em fevereiro de 2025, num arranjo em que o União Brasil comandou o Senado e o Republicanos a Câmara.', 'verified', false, '2025-02-01', 'https://www12.senado.leg.br/noticias/materias/2025/02/01/alcolumbre-e-reeleito-presidente-do-senado', 'other', 1, 'Plenário do Senado', 'Eleição Mesa Diretora', 'alcolumbre-reeleicao-senado-b165-3') ON CONFLICT (slug) DO NOTHING RETURNING id)
  INSERT INTO statement_categories (statement_id, category_id, is_primary) SELECT id, c_con, true FROM ins;

  -- 4 Bolsonaro sobre indiciamento PGR (fev/2025)
  WITH ins AS (INSERT INTO statements (politician_id, summary, full_quote, context, verification_status, is_featured, statement_date, primary_source_url, primary_source_type, severity_score, venue, event_name, slug) VALUES (v_jai, 'Bolsonaro nega tentativa de golpe após denúncia da PGR e ataca STF.', 'Nunca houve golpe. Isso é narrativa para me prender. O que existe é perseguição política da esquerda com ajuda de ministros do Supremo.', 'Após a PGR denunciar Bolsonaro por tentativa de golpe de Estado em fevereiro de 2025, o ex-presidente concedeu entrevista negando os fatos e atacando o Supremo Tribunal Federal.', 'verified', true, '2025-02-18', 'https://www.folha.uol.com.br/poder/2025/02/bolsonaro-denuncia-pgr-golpe.shtml', 'news_article', 5, 'Entrevista coletiva', 'Denúncia PGR Golpe', 'bolsonaro-nega-golpe-pgr-b165-4') ON CONFLICT (slug) DO NOTHING RETURNING id)
  INSERT INTO statement_categories (statement_id, category_id, is_primary) SELECT id, c_ant, true FROM ins UNION ALL SELECT id, c_des, false FROM ins;

  -- 5 Lula "mulher bonita" sobre Gleisi (mar/2025)
  WITH ins AS (INSERT INTO statements (politician_id, summary, full_quote, context, verification_status, is_featured, statement_date, primary_source_url, primary_source_type, severity_score, venue, event_name, slug) VALUES (v_lul, 'Lula gera polêmica ao apresentar Gleisi como "uma mulher bonita" em cerimônia.', 'Quero apresentar para vocês a Gleisi Hoffmann, uma mulher bonita, inteligente, competente, que vai assumir a Secretaria de Relações Institucionais.', 'Em cerimônia em março de 2025, ao anunciar a indicação de Gleisi Hoffmann para a SRI, Lula começou destacando a aparência física da então presidente do PT, gerando críticas de grupos feministas sobre a ordem dos adjetivos.', 'verified', true, '2025-03-06', 'https://www1.folha.uol.com.br/poder/2025/03/lula-gleisi-mulher-bonita-sri.shtml', 'news_article', 3, 'Palácio do Planalto', 'Anúncio SRI', 'lula-gleisi-mulher-bonita-b165-5') ON CONFLICT (slug) DO NOTHING RETURNING id)
  INSERT INTO statement_categories (statement_id, category_id, is_primary) SELECT id, c_mac, true FROM ins;

  -- 6 Damares posse CDH (fev/2025)
  WITH ins AS (INSERT INTO statements (politician_id, summary, full_quote, context, verification_status, is_featured, statement_date, primary_source_url, primary_source_type, severity_score, venue, event_name, slug) VALUES (v_dam, 'Damares assume presidência da CDH do Senado e anuncia cruzada contra "ideologia de gênero".', 'Vou presidir esta comissão com os valores da família brasileira. Vamos combater a ideologia de gênero que está destruindo nossas crianças.', 'Ao assumir a presidência da Comissão de Direitos Humanos do Senado em fevereiro de 2025, Damares Alves anunciou pauta conservadora e críticas a políticas de diversidade.', 'verified', true, '2025-02-12', 'https://www12.senado.leg.br/noticias/materias/2025/02/12/damares-assume-cdh', 'other', 3, 'Senado Federal', 'Posse CDH', 'damares-posse-cdh-b165-6') ON CONFLICT (slug) DO NOTHING RETURNING id)
  INSERT INTO statement_categories (statement_id, category_id, is_primary) SELECT id, c_hom, true FROM ins UNION ALL SELECT id, c_dis, false FROM ins;

  -- 7 Haddad IOF (mar/2025)
  WITH ins AS (INSERT INTO statements (politician_id, summary, full_quote, context, verification_status, is_featured, statement_date, primary_source_url, primary_source_type, severity_score, venue, event_name, slug) VALUES (v_had, 'Haddad defende revisão do IOF para combater elisão fiscal em remessas internacionais.', 'A mudança no IOF é necessária para coibir elisão fiscal de grandes patrimônios. Não é aumento de imposto sobre o trabalhador.', 'O ministro da Fazenda defendeu em março de 2025 a medida que ampliou o IOF sobre operações cambiais, justificando-a como medida de combate à elisão fiscal dos mais ricos.', 'verified', false, '2025-03-20', 'https://valor.globo.com/politica/noticia/2025/03/20/haddad-defende-iof-elisao.ghtml', 'news_article', 2, 'Ministério da Fazenda', 'IOF', 'haddad-iof-elisao-b165-7') ON CONFLICT (slug) DO NOTHING RETURNING id)
  INSERT INTO statement_categories (statement_id, category_id, is_primary) SELECT id, c_irr, true FROM ins;

  -- 8 Bolsonaro prisão domiciliar discurso (mar/2025)
  WITH ins AS (INSERT INTO statements (politician_id, summary, full_quote, context, verification_status, is_featured, statement_date, primary_source_url, primary_source_type, severity_score, venue, event_name, slug) VALUES (v_jai, 'Bolsonaro convoca apoiadores para ato na Paulista contra o STF e a "ditadura".', 'Precisamos ir para a Paulista. O Brasil vive uma ditadura togada. O povo tem que mostrar que não aceita essa perseguição.', 'Após decisões do STF ampliando restrições em seu processo, Bolsonaro convocou ato público na Avenida Paulista em março de 2025, classificando o Judiciário como ditatorial.', 'verified', true, '2025-03-15', 'https://g1.globo.com/politica/noticia/2025/03/15/bolsonaro-convoca-ato-paulista-stf.ghtml', 'news_article', 5, 'Redes sociais', 'Ato Paulista', 'bolsonaro-ato-paulista-ditadura-b165-8') ON CONFLICT (slug) DO NOTHING RETURNING id)
  INSERT INTO statement_categories (statement_id, category_id, is_primary) SELECT id, c_ant, true FROM ins UNION ALL SELECT id, c_ame, false FROM ins;

  -- 9 Gleisi posse SRI
  WITH ins AS (INSERT INTO statements (politician_id, summary, full_quote, context, verification_status, is_featured, statement_date, primary_source_url, primary_source_type, severity_score, venue, event_name, slug) VALUES (v_gle, 'Gleisi assume SRI prometendo reconstruir diálogo com Congresso após perda de votações.', 'Vou reconstruir a ponte com o Congresso. Erramos na comunicação e vamos corrigir. O governo precisa de maioria para aprovar pautas do povo.', 'Ao assumir a Secretaria de Relações Institucionais em março de 2025, Gleisi reconheceu desgastes do governo com o Congresso e prometeu mudança de postura.', 'verified', false, '2025-03-10', 'https://www.gov.br/planalto/noticias/2025/03/gleisi-posse-sri', 'other', 1, 'Palácio do Planalto', 'Posse SRI', 'gleisi-posse-sri-b165-9') ON CONFLICT (slug) DO NOTHING RETURNING id)
  INSERT INTO statement_categories (statement_id, category_id, is_primary) SELECT id, c_con, true FROM ins;

  -- 10 Nikolas ataca Moraes (fev/2025)
  WITH ins AS (INSERT INTO statements (politician_id, summary, full_quote, context, verification_status, is_featured, statement_date, primary_source_url, primary_source_type, severity_score, venue, event_name, slug) VALUES (v_nik, 'Nikolas Ferreira chama Alexandre de Moraes de "ditador de toga" em discurso na Câmara.', 'O Alexandre de Moraes é um ditador de toga. Ele prende quem pensa diferente. Isso não é República, isso é tirania judicial.', 'Discurso na tribuna da Câmara em fevereiro de 2025 após decisão de Moraes no inquérito sobre tentativa de golpe, com amplificação nas redes sociais.', 'verified', true, '2025-02-20', 'https://www.camara.leg.br/noticias/discurso-nikolas-moraes-2025', 'other', 4, 'Câmara dos Deputados', 'Tribuna', 'nikolas-moraes-ditador-toga-b165-10') ON CONFLICT (slug) DO NOTHING RETURNING id)
  INSERT INTO statement_categories (statement_id, category_id, is_primary) SELECT id, c_ant, true FROM ins UNION ALL SELECT id, c_dis, false FROM ins;

  -- 11
  WITH ins AS (INSERT INTO statements (politician_id, summary, full_quote, context, verification_status, is_featured, statement_date, primary_source_url, primary_source_type, severity_score, venue, event_name, slug) VALUES (v_edu, 'Eduardo Bolsonaro articula sanções dos EUA contra Moraes em viagem a Washington.', 'Estou nos EUA articulando para que autoridades americanas apliquem a Lei Magnitsky contra o ministro Alexandre de Moraes pelas perseguições no Brasil.', 'Em fevereiro de 2025, Eduardo Bolsonaro viajou aos EUA para encontros com políticos republicanos buscando sanções a Moraes com base na Lei Magnitsky.', 'verified', true, '2025-02-25', 'https://www1.folha.uol.com.br/poder/2025/02/eduardo-bolsonaro-magnitsky-moraes.shtml', 'news_article', 5, 'Washington, EUA', 'Articulação internacional', 'eduardo-magnitsky-moraes-b165-11') ON CONFLICT (slug) DO NOTHING RETURNING id)
