  -- 12
  WITH ins AS (INSERT INTO statements (politician_id, summary, full_quote, context, verification_status, is_featured, statement_date, primary_source_url, primary_source_type, severity_score, venue, event_name, slug) VALUES (v_fla, 'Flávio Bolsonaro afirma que "Bolsonaro será candidato" apesar de inelegibilidade.', 'Meu pai será candidato em 2026. A inelegibilidade vai cair. O povo decide, não ministro do TSE.', 'Em declaração no Senado em março de 2025, Flávio Bolsonaro reafirmou que o pai disputará as eleições de 2026, mesmo com inelegibilidade até 2030 determinada pelo TSE.', 'verified', false, '2025-03-05', 'https://oglobo.globo.com/politica/noticia/2025/03/flavio-bolsonaro-pai-candidato-2026.ghtml', 'news_article', 3, 'Senado Federal', 'Entrevista', 'flavio-bolsonaro-candidato-2026-b165-12') ON CONFLICT (slug) DO NOTHING RETURNING id)
