  WITH ins AS (INSERT INTO statements (politician_id, summary, full_quote, context, verification_status, is_featured, statement_date, primary_source_url, primary_source_type, severity_score, venue, event_name, slug) VALUES (v_tar, 'Tarcísio evita se declarar candidato presidencial mas diz "estarei onde o Bolsonaro mandar".', 'Não sou candidato a presidente. Meu candidato é Bolsonaro. Estarei onde ele determinar. Ponto final.', 'Em entrevista em janeiro de 2025, o governador de SP desconversou sobre candidatura presidencial e reafirmou lealdade a Bolsonaro, enquanto bastidores do PL discutiam plano B.', 'verified', true, '2025-01-22', 'https://g1.globo.com/sp/sao-paulo/noticia/2025/01/22/tarcisio-candidatura-2026-bolsonaro.ghtml', 'news_article', 2, 'Palácio dos Bandeirantes', 'Entrevista', 'tarcisio-candidato-bolsonaro-b165-13') ON CONFLICT (slug) DO NOTHING RETURNING id)
