  WITH ins AS (INSERT INTO statements (politician_id, summary, full_quote, context, verification_status, is_featured, statement_date, primary_source_url, primary_source_type, severity_score, venue, event_name, slug) VALUES (v_bia, 'Bia Kicis defende anistia ampla para envolvidos no 8 de janeiro.', 'Precisamos de anistia ampla, geral e irrestrita para os patriotas do 8 de janeiro. São presos políticos do regime de Moraes.', 'Em sessão da Câmara de fevereiro de 2025, Bia Kicis defendeu projeto de anistia para réus do 8 de janeiro, classificando-os como presos políticos.', 'verified', false, '2025-02-13', 'https://www.camara.leg.br/noticias/kicis-anistia-8-janeiro', 'other', 4, 'Câmara dos Deputados', 'Debate Anistia', 'kicis-anistia-8janeiro-b165-14') ON CONFLICT (slug) DO NOTHING RETURNING id)
